"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Pagination } from "@/components/ui/pagination";
import { Skeleton } from "@/components/ui/skeleton";
import { getDriverRequests, updateDriverRequestStatus } from "@/lib/api";
import { formatCurrency, formatDate } from "@/lib/utils";

type DriverRequestRow = {
  _id: string;
  shopName?: string;
  customerName?: string;
  orderDate?: string;
  createdAt: string;
  totalAmount?: number;
  price?: number;
  status: string;
  shopId?: {
    name?: string;
  };
};

type DriverRequestsResponse = {
  page: number;
  totalPage: number;
  requests: DriverRequestRow[];
};

export default function AdminDriversPage() {
  const queryClient = useQueryClient();
  const [page, setPage] = useState(1);

  const requestsQuery = useQuery({
    queryKey: ["admin-driver-requests", page],
    queryFn: () => getDriverRequests({ page, limit: 8 }),
  });

  const requests = requestsQuery.data as DriverRequestsResponse | undefined;

  const requestMutation = useMutation({
    mutationFn: ({ id, status }: { id: string; status: string }) => updateDriverRequestStatus(id, status),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-driver-requests"] });
      queryClient.invalidateQueries({ queryKey: ["admin-overview"] });
    },
  });

  return (
    <div className="space-y-5">
      <Card className="p-6">
        <h1 className="text-[32px] font-semibold leading-[120%] text-slate-900">Driver Requests</h1>
        <p className="mt-2 text-base font-medium leading-[120%] text-slate-500">Review delivery requests and approve or reject them.</p>
      </Card>
      <Card className="overflow-hidden">
        <div className="overflow-x-auto px-5 py-5">
          {requestsQuery.isLoading ? (
            <div className="space-y-3">
              {Array.from({ length: 5 }).map((_, index) => (
                <Skeleton key={index} className="h-20" />
              ))}
            </div>
          ) : (
            <table className="min-w-full text-left">
              <thead className="border-y border-slate-100 text-[13px] uppercase tracking-[0.16em] text-slate-400">
                <tr>
                  <th className="py-4">Shop</th>
                  <th className="py-4">Customer</th>
                  <th className="py-4">Order Date</th>
                  <th className="py-4">Total</th>
                  <th className="py-4">Status</th>
                  <th className="py-4 text-right">Action</th>
                </tr>
              </thead>
              <tbody>
                {requests?.requests?.map((request) => (
                  <tr key={request._id} className="border-b border-slate-100 last:border-b-0">
                    <td className="py-4 font-medium text-slate-900">{request.shopName || request.shopId?.name || "Shop"}</td>
                    <td className="py-4 text-slate-600">{request.customerName || "Customer"}</td>
                    <td className="py-4 text-slate-600">{formatDate(request.orderDate || request.createdAt)}</td>
                    <td className="py-4 font-semibold text-slate-900">{formatCurrency(request.totalAmount || request.price || 0)}</td>
                    <td className="py-4 capitalize text-slate-600">{request.status}</td>
                    <td className="py-4 text-right">
                      <div className="flex justify-end gap-2">
                        <Button size="sm" variant="secondary" onClick={() => requestMutation.mutate({ id: request._id, status: "accepted" })}>
                          Accept
                        </Button>
                        <Button size="sm" variant="destructive" onClick={() => requestMutation.mutate({ id: request._id, status: "rejected" })}>
                          Reject
                        </Button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
        <Pagination page={requests?.page || page} totalPages={requests?.totalPage || 1} onPageChange={setPage} />
      </Card>
    </div>
  );
}
